const REQUIRED_STATES={OPTIONAL:'optional',REQUIRED:'required'};const REQUIRED_STATES_ARRAY=Object.values(REQUIRED_STATES);function getCookie(name){const value=`; ${document.cookie}`;const parts=value.split(`; ${name}=`);if(parts.length===2)return parts.pop().split(';').shift();}
if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>{initOrderFormToggles();});}else{initOrderFormToggles();}
function initOrderFormToggles(){if(!document.querySelector('.order-form-option-table'))return;function updateVisualState(fieldId,value){const escapedId=fieldId.replace(/(["\\])/g,'\\$1');const requiredDropdown=document.querySelector(`.required-status-dropdown[data-field-id="${escapedId}"]`);const toggleInput=document.querySelector(`.toggle-switch[data-field-id="${escapedId}"] input`);if(!toggleInput)return;if(requiredDropdown){const wrapper=requiredDropdown.closest('.required-status-wrapper');if(value==='do_not_ask'){toggleInput.checked=false;requiredDropdown.disabled=true;if(wrapper){wrapper.classList.add('is-disabled');}}else{toggleInput.checked=true;requiredDropdown.disabled=false;requiredDropdown.value=value;requiredDropdown.dataset.current=value;if(wrapper){wrapper.dataset.current=value;wrapper.classList.remove('is-disabled');}}}else{toggleInput.checked=(value==='True'||value===true||value==='true');}}
document.querySelectorAll('input[type=hidden][name^="settings-order_"], input[type=hidden][name^="settings-attendee_"]').forEach(input=>{updateVisualState(input.id,input.value);});let currentOpenInfoBox=null;document.addEventListener('click',function(e){const toggle=e.target.closest('.info-toggle[data-toggle="info-box"]');if(toggle){const infoBox=toggle.nextElementSibling;if(infoBox?.classList.contains('inline-info-box')){if(currentOpenInfoBox&&currentOpenInfoBox!==infoBox){currentOpenInfoBox.classList.add('d-none');}
infoBox.classList.toggle('d-none');currentOpenInfoBox=infoBox.classList.contains('d-none')?null:infoBox;}
e.stopPropagation();return;}
if(e.target.closest('.inline-info-box, .info-toggle-wrapper')){return;}
if(currentOpenInfoBox){currentOpenInfoBox.classList.add('d-none');currentOpenInfoBox=null;}});document.querySelectorAll('.question-required-dropdown[data-question-id]').forEach(dropdown=>{dropdown.addEventListener('change',async function(){const questionId=this.dataset.questionId;const fieldName=this.getAttribute('aria-label')||'this field';const newValue=this.value==='required';const previousValue=this.dataset.current;const wrapper=this.closest('.required-status-wrapper');this.dataset.current=this.value;if(wrapper){wrapper.dataset.current=this.value;}
this.disabled=true;this.classList.add('loading');try{const csrfToken=getCookie('pretix_csrftoken')||getCookie('csrftoken');if(!csrfToken){throw new Error('CSRF token not found');}
const baseUrl=`${window.location.pathname.replace(/\/orderforms\/?$/, '')}`;const toggleUrl=`${baseUrl}/questions/${questionId}/toggle/`;const payload=JSON.stringify({field:'required',value:newValue});const response=await fetch(toggleUrl,{method:'POST',headers:{'Content-Type':'application/json','X-CSRFToken':csrfToken,},body:payload});if(!response.ok){const errorData=await response.json().catch(()=>({error:'Unknown error'}));throw new Error(errorData.error||`HTTP ${response.status}`);}
const originalBg=this.style.backgroundColor;this.style.backgroundColor='#d4edda';setTimeout(()=>{this.style.backgroundColor=originalBg;},500);}catch(error){console.error('Failed to update required status',{questionId,fieldName,error,});this.dataset.current=previousValue;this.value=previousValue;if(wrapper){wrapper.dataset.current=previousValue;}
alert(`Failed to update required status for ${fieldName}. Please try again or refresh the page.`);}finally{this.disabled=false;this.classList.remove('loading');}});});document.querySelectorAll('.required-status-dropdown[data-field-id]').forEach(dropdown=>{dropdown.addEventListener('change',function(){const fieldId=this.dataset.fieldId;const hiddenInput=document.getElementById(fieldId);const escapedId=fieldId.replace(/(["\\])/g,'\\$1');const checkbox=document.querySelector(`.toggle-switch[data-field-id="${escapedId}"] input`);if(!hiddenInput||!checkbox||!checkbox.checked){return;}
const newValue=this.value;if(!REQUIRED_STATES_ARRAY.includes(newValue)){return;}
hiddenInput.value=newValue;updateVisualState(fieldId,newValue);});});document.querySelectorAll('.toggle-switch[data-field-id] input').forEach(input=>{input.addEventListener('change',function(){const toggle=this.closest('.toggle-switch');const fieldId=toggle.dataset.fieldId;const escapedId=fieldId.replace(/(["\\])/g,'\\$1');const requiredDropdown=document.querySelector(`.required-status-dropdown[data-field-id="${escapedId}"]`);const hiddenInput=document.getElementById(fieldId);if(!hiddenInput)return;if(!requiredDropdown){hiddenInput.value=this.checked?'True':'False';}else{if(this.checked){let state=hiddenInput.dataset.previousState||requiredDropdown.value;if(!REQUIRED_STATES_ARRAY.includes(state)){state=REQUIRED_STATES.OPTIONAL;}
hiddenInput.value=state;updateVisualState(fieldId,state);delete hiddenInput.dataset.previousState;}else{if(hiddenInput.value!=='do_not_ask'){hiddenInput.dataset.previousState=hiddenInput.value;}
hiddenInput.value='do_not_ask';updateVisualState(fieldId,'do_not_ask');}}});});}
document.querySelectorAll('.question-active-toggle').forEach(toggle=>{toggle.addEventListener('change',function(){const label=this.closest('label');const toggleUrl=label.dataset.toggleUrl;const formData=new URLSearchParams();formData.append('field','active');formData.append('value',this.checked?'true':'false');fetch(toggleUrl,{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded','X-CSRFToken':document.querySelector('[name=csrfmiddlewaretoken]').value},body:formData.toString()}).then(resp=>{if(!resp.ok){alert('Failed to update custom field state');this.checked=!this.checked;}});});});;